import { create } from 'zustand'

export const useCountdownStore = create((set) => ({
    timeInput: {
        hours: '',
        minutes: '',
        seconds: ''
    },
    time: null,
    timeLeft: 0,
    initialSeconds: 0,
    isRunning: false,
    setTimeInput: (input) => set((state) => {
        const initial = (input.hours || 0) * 3600 + (input.minutes || 0) * 60 + (input.seconds || 0)
        return {
            timeInput: {
                ...state.timeInput,
                hours: input.hours,
                seconds: input.seconds,
                minutes: input.minutes
            },
            initialSeconds: initial,
            timeLeft: initial
        }
    }),
    start: () => set(() => ({

    })),
    pause: () => set(() => ({

    })),
    reset: () => set(() => ({

    })),
    setIsRunning: (isRunning) => set(() => ({
        isRunning
    }))
}))
